const toEmail = emailMatches ? emailMatches[0] : '';

const doc = $('Telegram Trigger').first().json.message?.document;
const fileName = doc?.file_name || 'photo.jpg';

// Récupérer le contenu extrait du document
const documentContent = $json.documentContent || '';
const extractionMethod = $json.extractionMethod || 'none';

// Récupérer le binary DIRECTEMENT depuis le node source
const fileNode = $('Récupérer Fichier Document').first();
const binaryData = fileNode.binary || {};
const inputBinary = $input.first().binary || {};
const finalBinary = Object.keys(binaryData).length > 0 ? binaryData : inputBinary;

// Préparer le prompt pour l'IA qui va composer l'email
