// Réponse OpenAI (depuis Composer Email IA = input direct)
const aiResponse = $input.all()[0].json;
let emailBody = "Veuillez trouver ci-joint le document demandé.";
if (aiResponse.choices && aiResponse.choices[0]) {
  emailBody = aiResponse.choices[0].message.content;
}

// Metadata depuis Extraire Email et Fichier
const extractData = $("Extraire Email et Fichier").first().json;
const toEmail = extractData.toEmail || "";
const fileName = extractData.fileName || "document.pdf";
const caption = extractData.caption || "";

// Subject = nom du fichier sans extension
let subject = fileName;
const extMatch = subject.match(/\.(pdf|docx|xlsx|doc|xls|csv|txt)$/i);
const fileExt = extMatch ? extMatch[0].toLowerCase() : "";
if (extMatch) {
  subject = subject.replace(/\.(pdf|docx|xlsx|doc|xls|csv|txt)$/i, "").trim();
}

// MimeType mapping
const mimeMap = {
  ".pdf": "application/pdf",
  ".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
  ".xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
  ".doc": "application/msword",
  ".csv": "text/csv",
  ".txt": "text/plain"
};
const mimeType = mimeMap[fileExt] || "application/octet-stream";

// BINARY : récupérer et normaliser sous la clé "data"
const sourceItem = $("Extraire Email et Fichier").first();
const sourceBinary = sourceItem.binary || {};
let finalBinary = {};

const keys = Object.keys(sourceBinary);
if (keys.length > 0) {
  const firstKey = keys[0];
  const binaryMeta = { ...sourceBinary[firstKey] };
  binaryMeta.fileName = fileName;
  if (!binaryMeta.mimeType || binaryMeta.mimeType === "application/octet-stream") {
    binaryMeta.mimeType = mimeType;
  }
  finalBinary = { data: binaryMeta };
} else {
  // Fallback depuis Récupérer Fichier Document
  const fileNodeBinary = $("Récupérer Fichier Document").first().binary || {};
  const fkeys = Object.keys(fileNodeBinary);
  if (fkeys.length > 0) {
    const binaryMeta = { ...fileNodeBinary[fkeys[0]] };
    binaryMeta.fileName = fileName;
    if (!binaryMeta.mimeType || binaryMeta.mimeType === "application/octet-stream") {
      binaryMeta.mimeType = mimeType;
    }
    finalBinary = { data: binaryMeta };
  }
}

// Convertir le message en HTML professionnel
const paragraphs = emailBody.split("\n\n");
const htmlParagraphs = paragraphs.map(p => {
  const escaped = p.replace(/\n/g, "<br>");
  return '<p style="margin:0 0 14px 0;line-height:1.6;font-size:14px;">' + escaped + "</p>";
}).join("");

const htmlMessage = '<div style="font-family:Segoe UI,Arial,sans-serif;max-width:600px;margin:0 auto;color:#333;">'
  + '<div style="padding:0 0 20px 0;">' + htmlParagraphs + "</div>"
  + '<div style="border-top:2px solid #1a73e8;padding-top:16px;margin-top:8px;">'
  + '<table cellpadding="0" cellspacing="0" border="0"><tr>'
  + '<td style="vertical-align:top;">'
  + '<div style="font-weight:700;color:#1a73e8;font-size:14px;">TalosPrimes</div>'
  + '<div style="font-size:12px;color:#666;margin-top:2px;">Cabinet de courtage en assurance &amp; gestion administrative</div>'
  + '<div style="font-size:12px;color:#666;margin-top:4px;">📧 direction@talosprimes.com</div>'
  + '<div style="font-size:11px;color:#999;margin-top:4px;"><a href="https://talosprimes.com" style="color:#1a73e8;text-decoration:none;">talosprimes.com</a></div>'
  + "</td></tr></table></div></div>";

return [{
  json: {
    toEmail,
    fileName,
    subject,
    message: htmlMessage,
    caption
  },
  binary: finalBinary
}];

