// Récupérer le document depuis static data
const staticData = $getWorkflowStaticData('global');
const doc = staticData.pendingDocument;

if (!doc || !doc.html) {
  return [{ json: { error: 'Aucun document en attente' } }];
}

// Créer le binary à partir du HTML
const htmlBuffer = Buffer.from(doc.html, 'utf-8');

// Nettoyer le static data
const docInfo = { ...doc };
delete docInfo.html;
delete staticData.pendingDocument;

return [{
  json: {
    ...docInfo,
    chatId: (() => {
      try { const v = $('Préparer Contexte (Voix)').first()?.json?.chatId; if(v) return v; } catch(e) {}
      try { return $('Préparer Contexte (Texte)').first()?.json?.chatId; } catch(e) {}
      return '6296082748';
    })()
  },
  binary: {
    data: {
      data: htmlBuffer.toString('base64'),
      mimeType: 'text/html',
      fileName: docInfo.fileName || 'document.html',
      fileExtension: 'html'
    }
  }
}];
